#region Visto Filter Tests
        [Fact]
        public void WFiltro_VistoEqualsIntMinValue_ShouldNotAddParameterOrWhereClause()
        {
            // Arrange
            var filtro = new FilterGraph
            {
                Visto = int.MinValue
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            result.Value.parametros.Should().NotContain(p => p.ParameterName.Contains(DBGraphDicInfo.Visto));
            result.Value.where.Should().NotContain(DBGraphDicInfo.Visto);
        }

        [Fact]
        public void WFiltro_VistoHasValidValue_ShouldAddParameterAndWhereClause()
        {
            // Arrange
            var VistoValue = 1;
            var filtro = new FilterGraph
            {
                Visto = VistoValue,
                LogicalOperator = " AND "
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            // Check parameter
            var VistoParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBGraphDicInfo.Visto}");
            VistoParameter.Should().NotBeNull();
            VistoParameter.Value.Should().Be(VistoValue);
            // Check where clause
            result.Value.where.Should().Contain($"[{DBGraphDicInfo.PTabelaNome}].[{DBGraphDicInfo.Visto}] = @{DBGraphDicInfo.Visto}");
        }

        [Fact]
        public void WFiltro_VistoWithDifferentValues_ShouldAddCorrectParameterValue()
        {
            // Arrange & Act & Assert for Visto = 0 (typically female)
            var filtroFemale = new FilterGraph
            {
                Visto = 0
            };
            var resultFemale = _serviceS.WFiltro(filtroFemale);
            resultFemale.Should().NotBeNull();
            var femaleParam = resultFemale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBGraphDicInfo.Visto}");
            femaleParam.Should().NotBeNull();
            femaleParam.Value.Should().Be(0);
            // Arrange & Act & Assert for Visto = 1 (typically male)
            var filtroMale = new FilterGraph
            {
                Visto = 1
            };
            var resultMale = _serviceS.WFiltro(filtroMale);
            resultMale.Should().NotBeNull();
            var maleParam = resultMale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBGraphDicInfo.Visto}");
            maleParam.Should().NotBeNull();
            maleParam.Value.Should().Be(1);
        }

        [Fact]
        public void WFiltro_VistoAsFirstFilter_ShouldNotIncludeLogicalOperatorInWhereClause()
        {
            // Arrange
            var filtro = new FilterGraph
            {
                Visto = 1,
                LogicalOperator = " AND "
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            result.Value.where.Should().StartWith($"[{DBGraphDicInfo.PTabelaNome}].[{DBGraphDicInfo.Visto}] = @{DBGraphDicInfo.Visto}");
            result.Value.where.Should().NotStartWith(" AND ");
        }

        [Fact]
        public void WFiltro_VistoWithOtherFilters_ShouldIncludeLogicalOperatorInWhereClause()
        {
            // Arrange
            var filtro = new FilterGraph
            {
                Guid = "Guid",
                Visto = 1,
                LogicalOperator = " AND "
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
